function process_refund($orderId, $amount = null, $reason = '')
        {
            $order = wc_get_order($orderId);

            if (! $order or ! $order->get_transaction_id())
            {
                return new WP_Error('error', __('Refund failed: No transaction ID', 'woocommerce'));
            }

            $client = $this->getRazorpayApiInstance();

            $paymentId = $order->get_transaction_id();

            $data = array(
                'amount'    =>  (int) round($amount * 100),
                'notes'     =>  array(
                    'reason'                =>  $reason,
                    'order_id'              =>  $orderId,
                    'refund_from_website'   =>  true,
                    'source'                =>  'woocommerce',
                )
            );

            try
            {
                $refund = $client->payment
                    ->fetch($paymentId)
                    ->refund($data);

                if (isset($refund) === true)
                {
                    $order->add_order_note(__('Refund Id: ' . $refund->id, 'woocommerce'));

                    do_action('woo_razorpay_refund_success', $refund->id, $orderId, $refund);

                    rzpLogInfo('Refund ID = ' . $refund->id .
                                ' , Refund speed requested = ' . $refund->speed_requested .
                                ' , Refund speed processed = ' . $refund->speed_processed);
                }

                return true;
            }
            catch(Exception $e)
            {
                $trackObject = $this->newTrackPluginInstrumentation();
                $properties = [
                    'error' => $e->getMessage()
                ];
                $trackObject->rzpTrackDataLake('razorpay.refund.failed', $properties);

                return new WP_Error('error', __($e->getMessage(), 'woocommerce'));
            }
        }

function set_from( $email, $name = '' ) {

		if ( ! filter_var( $email, FILTER_VALIDATE_EMAIL ) ) {
			return;
		}

		if ( ! empty( $name ) ) {
			$this->set_body_param(
				array(
					'from' => $name . ' <' . $email . '>',
				)
			);
		} else {
			$this->set_body_param(
				array(
					'from' => $email,
				)
			);
		}
	}

function makeCotationOrder( $postId ) {
		$result = ( new QuotationService() )->calculateQuotationByPostId( $postId );

		if ( $result ) {
			( new PayloadService() )->save( $postId );
		}

		if ( ! empty( $_SESSION[ Session::ME_KEY ]['quotation'] ) ) {
			unset( $_SESSION[ Session::ME_KEY ]['quotation'] );
		}

		return $result;
	}

function action_wp_footer() {
		global $wp_scripts, $wp_styles;

		$scripts = is_a( $wp_scripts, 'WP_Scripts' ) ? $wp_scripts->done : array();

		$scripts = apply_filters( 'infinite_scroll_existing_scripts', $scripts );

		$styles = is_a( $wp_styles, 'WP_Styles' ) ? $wp_styles->done : array();

		$styles = apply_filters( 'infinite_scroll_existing_stylesheets', $styles );

		?>
		<script type="text/javascript">
			(function() {
				var extend = function(out) {
					out = out || {};

					for (var i = 1; i < arguments.length; i++) {
						if (!arguments[i])
						continue;

						for (var key in arguments[i]) {
						if (arguments[i].hasOwnProperty(key))
							out[key] = arguments[i][key];
						}
					}

					return out;
				};
				extend( window.infiniteScroll.settings.scripts, <?php echo wp_json_encode( $scripts, JSON_UNESCAPED_SLASHES | JSON_HEX_TAG | JSON_HEX_AMP ); ?> );
				extend( window.infiniteScroll.settings.styles, <?php echo wp_json_encode( $styles, JSON_UNESCAPED_SLASHES | JSON_HEX_TAG | JSON_HEX_AMP ); ?> );
			})();
		</script>
		<?php
		$aria_live = 'assertive';
		if ( 'scroll' === self::get_settings()->type ) {
			$aria_live = 'polite';
		}
		?>
		<span id="infinite-aria" aria-live="<?php echo esc_attr( $aria_live ); ?>"></span>
		<?php
	}
